import { useState } from "react";
import { createPortal } from "react-dom";
import { logo } from "../../assets/images";
import styles from "./layout.module.scss"; 

export default function Header() {
  const headerRoot = document.getElementById("header");
  if (!headerRoot) return null;

  const [selectedLang, setSelectedLang] = useState("KO");

  return createPortal(
    <div className={styles.headerInner}>
      <ul>
        <li
          className={`hoverEffect ${selectedLang === "KO" ? styles.current : ""}`}
          onClick={() => setSelectedLang("KO")}
        >
          KO
        </li>
        <li>|</li>
        <li
          className={`hoverEffect ${selectedLang === "EN" ? styles.current : ""}`}
          onClick={() => setSelectedLang("EN")}
        >
          EN
        </li>
      </ul>

      <a href="/">
        <img src={logo} alt="Logo" />
      </a>

      <nav>
        <button type="button">
          <span></span>
          <span></span>
          <span></span>
        </button>
        <ol>
          <li className="hoverEffect"><a href="">HOME</a></li>
          <li className="hoverEffect"><a href="">PROFILE</a></li>
          <li className="hoverEffect"><a href="">PROJECTS</a></li>
          <li className="hoverEffect"><a href="">CONTACT</a></li>
        </ol>
      </nav>
    </div>,
    headerRoot
  );
}
